patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 0ca25bf89103..ee92383445a5 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -1013,10 +1013,27 @@ class BinOpSameOpcodeHelper {
           ToCIValue = APInt::getOneBitSet(FromCIValueBitWidth,
                                           FromCIValue.getZExtValue());
         } else {
-          assert(FromCIValue.isZero() && "Cannot convert the instruction.");
-          ToCIValue = ToOpcode == Instruction::And
-                          ? APInt::getAllOnes(FromCIValueBitWidth)
-                          : APInt::getZero(FromCIValueBitWidth);
+          // Check if the non-constant operand is zero, which makes the shift
+          // result zero regardless of the shift amount.
+          Value *NonConstOp = I->getOperand(1 - Pos);
+          if (auto *NonConstCI = dyn_cast<ConstantInt>(NonConstOp)) {
+            if (NonConstCI->isZero()) {
+              // The shift result is zero, so we can convert to any compatible op
+              ToCIValue = ToOpcode == Instruction::And
+                              ? APInt::getAllOnes(FromCIValueBitWidth)
+                              : APInt::getZero(FromCIValueBitWidth);
+            } else {
+              assert(FromCIValue.isZero() && "Cannot convert the instruction.");
+              ToCIValue = ToOpcode == Instruction::And
+                              ? APInt::getAllOnes(FromCIValueBitWidth)
+                              : APInt::getZero(FromCIValueBitWidth);
+            }
+          } else {
+            assert(FromCIValue.isZero() && "Cannot convert the instruction.");
+            ToCIValue = ToOpcode == Instruction::And
+                            ? APInt::getAllOnes(FromCIValueBitWidth)
+                            : APInt::getZero(FromCIValueBitWidth);
+          }
         }
         break;
       case Instruction::Mul:

